import React, { useEffect } from 'react';
import AOS from 'aos';
import styled from 'styled-components';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faLaptopCode, faCodeBranch, faUsersCog, faChalkboardTeacher, faTrophy, faCode, faCalendarAlt } from '@fortawesome/free-solid-svg-icons';
import { useTheme } from '../context/ThemeContext';

const Section = styled.section`
  padding: 100px 10%;
  text-align: center;
  position: relative;
  overflow: hidden;
`;

const Title = styled.h2`
  font-size: 2.5rem;
  color: #00FFFF;
  margin-bottom: 20px;
  position: relative;
  z-index: 2;

  &::after {
    content: '';
    display: block;
    width: 60px;
    height: 3px;
    background: linear-gradient(to right, #00FFFF, #00BFFF);
    margin: 10px auto;
  }
`;

const Cards = styled.div`
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 30px;
  margin-top: 50px;
`;

const Card = styled.div`
  background: rgba(255, 255, 255, 0.05);
  border-radius: 20px;
  padding: 40px 30px;
  width: 280px;
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: transform 0.3s ease, box-shadow 0.3s ease;

  &:hover {
    transform: translateY(-10px);
    box-shadow: 0 15px 30px rgba(0, 255, 255, 0.1);
  }

  i {
    font-size: 2.5rem;
    color: #00FFFF;
    margin-bottom: 20px;
  }

  h3 {
    font-size: 1.5rem;
    color: white;
    margin: 15px 0;
  }

  p {
    color: rgba(255, 255, 255, 0.8);
    line-height: 1.6;
  }
`;

const HighlightSection = styled.section`
  padding: 80px 20px;
  background: ${props => props.theme.cardBackground};
  transition: all 0.3s ease;
`;

const Container = styled.div`
  max-width: 1200px;
  margin: 0 auto;
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 40px;
  text-align: center;
`;

const StatCard = styled.div`
  padding: 30px;
  background: ${props => props.theme.background};
  border-radius: 15px;
  transition: all 0.3s ease;
  border: 1px solid ${props => props.theme.cardBorder};

  .icon {
    font-size: 2.5rem;
    color: ${props => props.theme.primary};
    margin-bottom: 15px;
    transition: all 0.3s ease;
  }

  h3 {
    color: ${props => props.theme.primary};
    font-size: 2.5rem;
    margin: 10px 0;
    font-weight: bold;
  }

  p {
    color: ${props => props.theme.text};
    font-size: 1.1rem;
  }

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 5px 15px ${props => props.theme.shadowColor};

    .icon {
      transform: scale(1.1);
    }
  }
`;

const Highlights = () => {
  useEffect(() => {
    AOS.init({
      duration: 800,
      once: true
    });
  }, []);

  const highlights = [
    {
      icon: faLaptopCode,
      title: "Workshops",
      description: "Hands-on learning in Web, AI, IoT & more. Master new skills with expert guidance."
    },
    {
      icon: faCodeBranch,
      title: "Hackathons",
      description: "Innovate & compete in exciting challenges. Turn ideas into reality in 48 hours."
    },
    {
      icon: faUsersCog,
      title: "Team Projects",
      description: "Build real-world solutions together. Collaborate and create impactful projects."
    },
    {
      icon: faChalkboardTeacher,
      title: "Tech Talks",
      description: "Sessions with industry experts & alumni. Learn from the best in the field."
    }
  ];

  return (
    <Section id="highlights">
      <Title data-aos="fade-up">What We Do</Title>
      <Cards>
        {highlights.map((item, index) => (
          <Card
            key={index}
            data-aos="fade-up"
            data-aos-delay={100 * (index + 1)}
          >
            <FontAwesomeIcon icon={item.icon} size="2x" color="#00FFFF" />
            <h3>{item.title}</h3>
            <p>{item.description}</p>
          </Card>
        ))}
      </Cards>
    </Section>
  );
};

const Highlight = () => {
  const { theme } = useTheme();

  const stats = [
    {
      icon: faTrophy,
      number: "50+",
      text: "Awards Won"
    },
    {
      icon: faCode,
      number: "100+",
      text: "Projects Completed"
    },
    {
      icon: faCalendarAlt,
      number: "30+",
      text: "Events Organized"
    }
  ];

  return (
    <HighlightSection theme={theme}>
      <Container>
        <StatsGrid>
          {stats.map((stat, index) => (
            <StatCard key={index} theme={theme}>
              <FontAwesomeIcon icon={stat.icon} className="icon" />
              <h3>{stat.number}</h3>
              <p>{stat.text}</p>
            </StatCard>
          ))}
        </StatsGrid>
      </Container>
    </HighlightSection>
  );
};

export { Highlights, Highlight };
